import { writeOutput } from "./codegen";

const DOCS_URL = "https://drive9.ai/SKILL.md";
const PLACEHOLDER_VALUE = "drive9_sk_CoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from drive9 API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:drive9",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const drive9Firewall = {",
    '  name: "drive9",',
    '  description: "drive9 API",',
    "  placeholders: {",
    `    DRIVE9_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.drive9.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.DRIVE9_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating drive9 firewall config...");
  const ts = generateTypeScript();
  writeOutput("drive9", ts, import.meta.dirname);
}
